import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { dashboardAPI } from '../../services/api';
import Card from '../../components/common/Card';
import StatCard from '../../components/common/StatCard';
import { User, FileText, Award, AlertTriangle, GraduationCap, BookOpen, TrendingUp } from 'lucide-react';

const StudentDashboard = () => {
  const { user } = useAuth();
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const response = await dashboardAPI.getStats();
      if (response.data.success) {
        setStats(response.data.stats);
      }
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-20">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-green-600"></div>
      </div>
    );
  }

  const profile = stats?.profile;

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Welcome Header */}
      <div className="bg-gradient-to-r from-green-600 via-green-700 to-green-800 rounded-2xl p-8 text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 w-40 h-40 bg-white/10 rounded-full -translate-y-1/2 translate-x-1/2"></div>
        <div className="absolute bottom-0 left-1/4 w-20 h-20 bg-white/5 rounded-full translate-y-1/2"></div>
        <div className="relative z-10">
          <div className="flex items-center gap-2 text-green-200 mb-2">
            <GraduationCap className="w-5 h-5" />
            <span className="text-sm font-medium">Student Portal</span>
          </div>
          <h1 className="text-3xl font-bold mb-2">
            Welcome, {profile?.first_name} {profile?.last_name}!
          </h1>
          <p className="text-green-100">
            Student ID: {profile?.student_id} | {profile?.year_level} - {profile?.section}
          </p>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
        <StatCard
          title="Pending Violations"
          value={stats?.pendingViolations || 0}
          icon={AlertTriangle}
          color="orange"
          subtitle="Requires attention"
        />
        <StatCard
          title="Certificates"
          value={stats?.certificateCount || 0}
          icon={Award}
          color="blue"
          subtitle="Uploaded"
        />
        <StatCard
          title="Achievements"
          value={stats?.achievementCount || 0}
          icon={TrendingUp}
          color="green"
          subtitle="Earned"
        />
      </div>

      {/* Profile Info */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <Card title="Personal Information" icon={User}>
          <div className="space-y-1">
            {[
              { label: 'Student ID', value: profile?.student_id },
              { label: 'Full Name', value: `${profile?.first_name || ''} ${profile?.middle_name || ''} ${profile?.last_name || ''}`.trim() },
              { label: 'Gender', value: profile?.gender },
              { label: 'Contact', value: profile?.contact_number },
              { label: 'Address', value: profile?.address },
            ].map((item, index) => (
              <div key={index} className="flex justify-between py-3 border-b border-secondary-100 last:border-0 hover:bg-secondary-50 -mx-2 px-2 rounded transition-colors">
                <span className="text-secondary-500 text-sm">{item.label}</span>
                <span className="font-medium text-secondary-800 text-sm">{item.value || 'N/A'}</span>
              </div>
            ))}
          </div>
        </Card>

        <Card title="Academic Information" icon={BookOpen}>
          <div className="space-y-1">
            <div className="flex justify-between py-3 border-b border-secondary-100 hover:bg-secondary-50 -mx-2 px-2 rounded transition-colors">
              <span className="text-secondary-500 text-sm">Year Level</span>
              <span className="font-medium text-secondary-800 text-sm">{profile?.year_level || 'N/A'}</span>
            </div>
            <div className="flex justify-between py-3 border-b border-secondary-100 hover:bg-secondary-50 -mx-2 px-2 rounded transition-colors">
              <span className="text-secondary-500 text-sm">Section</span>
              <span className="font-medium text-secondary-800 text-sm">{profile?.section || 'N/A'}</span>
            </div>
            <div className="flex justify-between py-3 border-b border-secondary-100 hover:bg-secondary-50 -mx-2 px-2 rounded transition-colors">
              <span className="text-secondary-500 text-sm">Status</span>
              <span className={`font-medium px-3 py-1 rounded-full text-xs ${
                profile?.status_record === 'Regular' ? 'bg-green-100 text-green-700' :
                profile?.status_record === 'Irregular' ? 'bg-yellow-100 text-yellow-700' :
                'bg-red-100 text-red-700'
              }`}>
                {profile?.status_record || 'N/A'}
              </span>
            </div>
            <div className="flex justify-between py-3 border-b border-secondary-100 hover:bg-secondary-50 -mx-2 px-2 rounded transition-colors">
              <span className="text-secondary-500 text-sm">Organization Role</span>
              <span className="font-medium text-secondary-800 text-sm">{profile?.organization_role || 'N/A'}</span>
            </div>
            <div className="flex justify-between py-3 hover:bg-secondary-50 -mx-2 px-2 rounded transition-colors">
              <span className="text-secondary-500 text-sm">Guardian</span>
              <span className="font-medium text-secondary-800 text-sm">{profile?.guardian_name || 'N/A'}</span>
            </div>
          </div>
        </Card>
      </div>

      {/* Skills */}
      <Card title="Skills & Sports" icon={Award}>
        <div className="flex flex-wrap gap-2">
          {stats?.skills?.map((skill, index) => (
            <span
              key={index}
              className={`px-4 py-2 rounded-lg text-sm font-medium ${
                skill.type === 'technical'
                  ? 'bg-blue-50 text-blue-700 border border-blue-200'
                  : 'bg-orange-50 text-orange-700 border border-orange-200'
              }`}
            >
              {skill.name}
            </span>
          ))}
          {(!stats?.skills || stats.skills.length === 0) && (
            <div className="empty-state w-full py-6">
              <Award className="w-8 h-8" />
              <p className="text-sm">No skills recorded</p>
            </div>
          )}
        </div>
      </Card>

      {/* Recent Violations */}
      <Card title="Recent Violations" icon={AlertTriangle}>
        {stats?.recentViolations?.length > 0 ? (
          <div className="space-y-2">
            {stats.recentViolations.map((violation) => (
              <div
                key={violation.id}
                className="flex items-center justify-between py-3 border-b border-secondary-100 last:border-0 hover:bg-secondary-50 -mx-2 px-2 rounded-lg transition-colors"
              >
                <div>
                  <p className="font-medium text-secondary-800">{violation.violation_type}</p>
                  <p className="text-sm text-secondary-500">{violation.date}</p>
                </div>
                <span className={`px-3 py-1.5 rounded-full text-xs font-medium ${
                  violation.status === 'Pending'
                    ? 'bg-yellow-100 text-yellow-700 border border-yellow-200'
                    : 'bg-green-100 text-green-700 border border-green-200'
                }`}>
                  {violation.status}
                </span>
              </div>
            ))}
          </div>
        ) : (
          <div className="empty-state py-8">
            <AlertTriangle className="w-8 h-8" />
            <p className="text-sm">No violations recorded</p>
            <p className="text-xs text-secondary-400 mt-1">Keep up the good work!</p>
          </div>
        )}
      </Card>
    </div>
  );
};

export default StudentDashboard;
